sp_angular_provider.script:
/* Use this Directive to add icons for the different types of Comments a Task can have to a table cell with a hover popover function
//
// Copyrights belong to Discover Technologies LLC. © 2023 Discover Technologies LLC
// Script Continued Below
// 2.8.1 | 2023-04-04 | mmcc | STRY0135723 - Homepage Comments column replaced by Task Comments
//  Created Directive
// 2.8.1 | 2023-04-19 | mmcc | STRY0135713 - Modal showing all comments when clicking the Response Column;
//  Rename directive and change usage of User to Response
//  Updated above Usage in a widget's HTML section to show use of new var names, item.directive_reopen_comments
//  Added dtechSysId, dtechTable and _openModalResponseComments()
// 2.8.1 | 2023-05-11 | mmcc | STRY0139742 - Increase delaying when hover directives open
//  Added CONST_POPOVER_DELAY, d._isClosing, d.initTooltip, d.popoverDelay;
//  In function _init(element) added setting d.popoverDelay = CONST_POPOVER_DELAY;
//  Added function _initTooltip(); in function _leaveTooltip() set d._isClosing = true;
//   Added function _popoverDelay(); in function _showDuration(event) set d._isClosing = false;
// 2.8.5 | 2023-07-07 | mmcc | STRY0137588 - View Comment on Detailed Status
//    Added dtechResponseColumnStyle which can be contentOnly, contentAndIcons, iconsOnly or allComments
//    Added dtechContentComment to hold HTML string which is used in contentOnly or contentAndIcons
// 2.8.5 | 2023-07-24 | mmcc | STRY0135715 - Edit privilege for my comments in the All Responses Modal
//    Added dtech-response-editor-control and dtechResponseEditorControl;
// 2.8.5 | 2023-09-01 | mmcc | DFCT0012141 - A Task with a Work Item Type of review will not need to show icons and text for 
//  fields Response Comments or Rework Comments
//    Added dtechWorkItemType
//
*/
function dtechResponseComments(getTemplateUrl, spModal, $timeout, $window) {
	// 2.8.1 | 2023-05-11 | mmcc | STRY0139742 - Increase delaying when hover directives open; 400 to 600
	var dtResponse = {
		restrict: 'E',
		//replace: true,
		// @: string 1 way, =: object 2 way, <: object 1 way
		scope: {
			dtechIsModal: "<",
			dtechPopoverPlacement: '@?',
			dtechReopenComments: '@',
			dtechResponseComments: '@',
			dtechReviewerComments: '@',
			dtechReworkComments: '@',
			dtechShowLabel: "<?",
			dtechInDataTable: "<?",
			dtechSysId: '@',
			dtechTable: '@',
			dtechResponseColumnStyle: '@',
			dtechContentComment: '@',
			// 2.8.5 | 2023-07-24 | mmcc | STRY0135715 - Edit privilege for my comments in the All Responses Modal; added
			dtechResponseEditorControl: '@',
			// 2.8.5 | 2023-09-01 | mmcc | DFCT0012141 - Task Work Item Type of review will not show icons and text; added
			dtechWorkItemType: '@'
		},
		controller: responseCtrl,
		link: link,
		controllerAs: 'd',
		templateUrl: getTemplateUrl('x_153465_discovert_dtechResponseComments.html')
	};
	return dtResponse;

	function responseCtrl($scope, $attrs, $animate, $sce) {
		var d = this;	

		// TODO: get from a service
		var CONST_TEMP_WAIT_DURATION = 600;
		// 2.8.1 | 2023-05-11 | mmcc | STRY0139742 - Increase delaying when hover directives open; TODO: get from a service
		var CONST_POPOVER_DELAY = 1200;
		// 2.8.5 | 2023-07-07 | mmcc | STRY0137588 - View Comment on Detailed Status; added
		var CONST_SPINNER_DELAY = 500;
		var CONST_CUT_OFF_VALUE = 160;

		var isOverTooltip = false;
		// 2.8.1 | 2023-05-11 | mmcc | STRY0139742 - Increase delaying when hover directives open; added, init to false
		var isClosing = false;

		var parentMouseLeaveTimeouts = [];  // added an array to collect each time mouse leave fires; need to cancel time-outs on destroy

		$scope.dtechResponseToolTipOpen = false;

		// directive's functional section
		d.enterTooltip = _enterTooltip;
		d.init = _init;

		// 2.8.1 | 2023-05-11 | mmcc | STRY0139742 - Increase delaying when hover directives open; added
		d.initTooltip = _initTooltip;

		d.leaveTooltip = _leaveTooltip;
		d.openModal = _openModal;
		d.openModalResponseComments = _openModalResponseComments;
		d.parentMouseLeave = _parentMouseLeave;

		d.popoverDelay = CONST_POPOVER_DELAY;

		d.showResponse = _showResponse;

		// when the user hovers over the tooltip set overtooltip flag
		function _enterTooltip() {
			isOverTooltip = true;
		}

		// init()
		// initialize the control, called from the Link function
		// gets a reference to the element
		function _init(rawAttrs) {
			// Set a default value when attribute not in hosting HTML
			if (angular.isUndefined(rawAttrs.dtechPopoverPlacement)) {
				$scope.dtechPopoverPlacement = "auto";
			}

			// Set a default value when attribute not in hosting HTML
			if (angular.isUndefined(rawAttrs.dtechShowLabel)) {
				$scope.dtechShowLabel = false;
			}

			if (angular.isUndefined(rawAttrs.dtechInDataTable)) {
				$scope.dtechInDataTable = false;
			}

			$scope.dtechResponseToolTipOpen = 
				angular.isDefined(rawAttrs.enterTooltip) ?
				$scope.$parent.$eval(rawAttrs.dtechResponseToolTipOpen) : false;

		}

		// 2.8.5 | 2023-07-07 | mmcc | STRY0137588 - View Comment on Detailed Status; added local function
		function _convertHtmlToString(someHtmlText) {
            var divElement = document.createElement('div');
            divElement.innerHTML = someHtmlText;
            return divElement.textContent || divElement.innerHTML || '';
        }

		// 2.8.5 | 2023-07-07 | mmcc | STRY0137588 - View Comment on Detailed Status; added global function
		$scope.truncateConvertedHtml = function(someHtmlText) {
			var convertedHtml = '';
            convertedHtml = _convertHtmlToString(someHtmlText);

			$scope.convertedHtmlLength = convertedHtml.length;

			convertedHtml = convertedHtml.substring(0, CONST_CUT_OFF_VALUE);

			if ($scope.convertedHtmlLength > CONST_CUT_OFF_VALUE) {
				convertedHtml = convertedHtml + '...';
			}

			return convertedHtml;
        };

		// 2.8.1 | 2023-05-11 | mmcc | STRY0139742 - Increase delaying when hover directives open; added function
		function _initTooltip() {
			// if the user moved off of the parent before the tooltip opened, cancel the open
			if (isClosing == true) {
				_leaveTooltip();
				isClosing = false;
			}
		}

		function _leaveTooltip() {
			isOverTooltip = false;
			$scope.dtechResponseToolTipOpen = false;
			// 2.8.1 | 2023-05-11 | mmcc | STRY0139742 - Increase delaying when hover directives open; set true
			isClosing = true;
		}

		// openModal()
		// this function is called from Template html
		// it is called when a user clicks on the open link
		function _openModal(event) {
			_openModalResponseComments(event);

		}

		function _openModalResponseComments(event) {
			var title = '';
			var widget = 'tasker_modal_response_comments';
			spModal.open({
				title: title,
				backdrop: 'static',
				widget: widget,
				widgetInput: {
					isModal: $scope.dtechIsModal,
					sys_id: $scope.dtechSysId,
					table:  $scope.dtechTable,
					// 2.8.5 | 2023-07-24 | mmcc | STRY0135715 - Edit privilege for my comments in the All Responses Modal; added
					responseEditorControl: $scope.dtechResponseEditorControl
				},
				size: 'lg',
				buttons: [],
				headerStyle: {
					'border-bottom': 'none',
					'padding': '20px 15px 0 20px'
				},
				footerStyle: {
					'display': 'none'
				}
			});

			// modal is openened stop the row or cell click form raising
			event.stopPropagation();

			_leaveTooltip();
		}

		function _parentMouseLeave() {
			// STRY0145237 - Directive - Duration code changes to match design; 
			// we need to track each time the below fires so we cancel on destroy
			parentMouseLeaveTimeouts.push($timeout(function() {
				if(!isOverTooltip){
					d.leaveTooltip();
				}
			}, CONST_TEMP_WAIT_DURATION));
		}

		function _showResponse(event) {
			$scope.dtechResponseToolTipOpen = true;
// TODO - ADD CALL TO GET DATA IF NOT POPULATED
			// 2.8.1 | 2023-05-11 | mmcc | STRY0139742 - Increase delaying when hover directives open; set false
			isClosing = false;
		}

		// STRY0145237 - Directive - Duration code changes to match design; added
		$scope.$on("$destroy", function (event) {
			// we tracked each time mouse leave fired, now we can cancel each time-out and remove from the array
			angular.forEach(parentMouseLeaveTimeouts, function(item) {
				$timeout.cancel(item);
				parentMouseLeaveTimeouts.splice(parentMouseLeaveTimeouts.indexOf(item), 1);
			});
		});

	} // end function responseCtrl

	// Link function links local methods to parent controller methods
	// see the list of events being monitored
	function link(scope, element, attrs, responseCtrl) {
		// initialize the control
		responseCtrl.init(attrs);

		scope.$on('$destroy',_destroy);

		function _destroy() {
			element.remove();
		}
	}

}
